/**
 * LLM Eval Types — Scenario definitions, scoring, and provider abstractions.
 *
 * The eval harness tests whether LLMs can correctly use ARC-1's MCP tools
 * by sending natural language prompts and scoring the generated tool calls.
 */

// ─── Tool Call Types ────────────────────────────────────────────────

/** A tool call generated by the LLM */
export interface LLMToolCall {
  name: string;
  arguments: Record<string, unknown>;
}

/** Result returned to the LLM after a tool call */
export interface ToolCallResult {
  content: string;
  isError?: boolean;
}

// ─── Scenario Types ─────────────────────────────────────────────────

/** A single expected tool call with optional parameter checks */
export interface ExpectedToolCall {
  /** Tool name (e.g., "SAPRead") */
  tool: string;
  /** Required parameters — each must match exactly */
  requiredArgs?: Record<string, unknown>;
  /** Parameters that must be present (value doesn't matter) */
  requiredArgKeys?: string[];
  /**
   * Content checks for string arguments. Every required pattern must match and every forbidden
   * pattern must not match. This lets evals score semantic syntax constraints without requiring
   * one byte-identical SQL/source spelling.
   */
  argumentPatterns?: Record<string, { required?: RegExp[]; forbidden?: RegExp[] }>;
}

/**
 * An eval scenario tests a single natural language prompt against
 * expected tool call behavior. Supports tiered scoring:
 * - optimal: the best tool call(s) — full score
 * - acceptable: valid alternatives — partial score
 * - forbidden: tools that must NOT be called — penalty
 */
export interface EvalScenario {
  /** Unique scenario identifier */
  id: string;
  /** Human-readable description */
  description: string;
  /** The natural language prompt sent to the LLM */
  prompt: string;
  /** Category for grouping results (e.g., "read", "search", "workflow") */
  category: string;
  /** Tags for filtering (e.g., ["single-step", "btp"]) */
  tags?: string[];

  /** The optimal (best) first tool call — scores 1.0 */
  optimal: ExpectedToolCall[];
  /** Acceptable alternative first tool calls — scores 0.5 */
  acceptable?: ExpectedToolCall[];
  /** Tools that must NOT be called — if called, score is 0 */
  forbidden?: string[];

  /** Require every expected parameter check to pass, regardless of the weighted overall score. */
  requireFullParameters?: boolean;

  /**
   * Mock responses keyed by tool name.
   * When the LLM calls a tool, the harness returns the matching mock
   * instead of calling the real MCP server. This enables offline eval.
   *
   * Format: { "SAPRead": "REPORT zhello.\nWRITE: / 'Hello'." }
   * Use "*" as a catch-all fallback.
   */
  mockResponses?: Record<string, string>;

  /**
   * For multi-step scenarios: the expected tool call sequence.
   * Each entry is a step with expected tool calls.
   * If provided, scoring checks the full trace, not just the first call.
   */
  expectedTrace?: ExpectedToolCall[][];

  /** Maximum number of tool calls the LLM should make */
  maxToolCalls?: number;
}

// ─── Scoring Types ──────────────────────────────────────────────────

/** Score for a single eval scenario */
export interface ScenarioScore {
  scenarioId: string;
  /** 0.0 = wrong, 0.5 = acceptable, 1.0 = optimal */
  toolSelectionScore: number;
  /** 0.0 = wrong params, 1.0 = all required params correct */
  parameterScore: number;
  /** Combined weighted score */
  overallScore: number;
  /** Number of tool calls made */
  toolCallCount: number;
  /** The actual tool calls captured */
  trace: LLMToolCall[];
  /** Total tokens used (input + output) */
  totalTokens?: number;
  /** Wall-clock duration in ms */
  durationMs: number;
  /** Human-readable explanation of the score */
  explanation: string;
  /** Whether it passed the overall threshold and any scenario-specific parameter requirement */
  passed: boolean;
}

/** Aggregated results for an eval run */
export interface EvalRunResult {
  /** Model identifier (e.g., "llama3.1:8b", "claude-sonnet-4-20250514") */
  model: string;
  /** Tool mode used ("standard" or "hyperfocused") */
  toolMode: 'standard' | 'hyperfocused';
  /** Timestamp */
  timestamp: string;
  /** Individual scenario scores */
  scores: ScenarioScore[];
  /** Aggregate metrics */
  summary: {
    totalScenarios: number;
    passed: number;
    failed: number;
    avgToolSelectionScore: number;
    avgParameterScore: number;
    avgOverallScore: number;
    avgToolCalls: number;
    avgDurationMs: number;
    totalTokens: number;
  };
}

// ─── Provider Types ─────────────────────────────────────────────────

/** Tool definition in OpenAI function-calling format */
export interface ToolDefinitionForLLM {
  type: 'function';
  function: {
    name: string;
    description: string;
    parameters: Record<string, unknown>;
  };
}

/** LLM response that may contain tool calls */
export interface LLMResponse {
  /** Text content (if the LLM responded with text) */
  content?: string;
  /** Tool calls (if the LLM wants to call tools) */
  toolCalls?: LLMToolCall[];
  /** Token usage */
  usage?: {
    promptTokens: number;
    completionTokens: number;
    totalTokens: number;
  };
  /** Whether the LLM is done (no more tool calls) */
  done: boolean;
}

/** Message in the conversation */
export interface Message {
  role: 'system' | 'user' | 'assistant' | 'tool';
  content?: string;
  toolCalls?: LLMToolCall[];
  /** For tool result messages */
  toolCallId?: string;
  toolName?: string;
}

/** Abstract LLM provider interface */
export interface LLMProvider {
  /** Provider name for logging */
  name: string;
  /** Model identifier */
  model: string;
  /** Send messages and get a response (single turn) */
  chat(messages: Message[], tools: ToolDefinitionForLLM[]): Promise<LLMResponse>;
}
